class Solution:
    def findErrorNums(self, nums: List[int]) -> List[int]:
        n=len(nums); s=n*(n+1)//2; ss=n*(n+1)*(2*n+1)//6
        for x in nums: s-=x; ss-=x*x
        diff=ss//s; return [(s+diff)//2, (diff-s)//2]

