class Solution {
public:
    vector<int> findErrorNums(vector<int>& nums) {
        int n=nums.size(); long s=n*(n+1)/2, ss=n*(n+1)*(2LL*n+1)/6;
        for(int x:nums){ s-=x; ss-=1LL*x*x; }
        long diff=ss/s; return {(int)((s+diff)/2),(int)((diff-s)/2)};
    }
};
